+namespace Microsoft.Integration.Shopify;
+
+using Microsoft.Sales.Document;
+using Microsoft.Utilities;
+
+/// <summary>
+/// Codeunit Shpfy Copy Document (ID 30366).
+/// </summary>
+codeunit 30366 "Shpfy Copy Document"
+{
+    Access = Internal;
+
+    [EventSubscriber(ObjectType::Codeunit, Codeunit::"Copy Document Mgt.", 'OnBeforeClearInvoiceAndShip', '', false, false)]
+    local procedure OnBeforeClearInvoiceAndShip(var ToSalesHeader: Record "Sales Header"; var IsHandled: Boolean)
+    begin
+        // Clear Shopify Order ID, Order No., and Refund ID when copying documents
+        // to ensure the new invoice/document is not linked to the original Shopify order
+        ToSalesHeader."Shpfy Order Id" := 0;
+        ToSalesHeader."Shpfy Order No." := '';
+        ToSalesHeader."Shpfy Refund Id" := 0;
+    end;
+}

