+    local procedure ConvertNonDeductibleVATAmtToJobCurrency(var JobJnlLine: Record "Job Journal Line"; PurchHeader: Record "Purchase Header"; PurchLine: Record "Purchase Line"; var NonDeductibleVATAmtPerUnitLCY: Decimal; var NonDeductibleVATAmtPerUnit: Decimal)
+    var
+        ConvertedNonDeductibleVATAmt: Decimal;
+    begin
+        // Adjust sign based on unit cost sign
+        if JobJnlLine."Unit Cost" > 0 then begin
+            NonDeductibleVATAmtPerUnit := Abs(NonDeductibleVATAmtPerUnit);
+            NonDeductibleVATAmtPerUnitLCY := Abs(NonDeductibleVATAmtPerUnitLCY);
+        end;
+
+        // Add Non-Deductible VAT amount to unit costs in the appropriate currency
+        case JobJnlLine."Currency Code" of
+            '':
+                // Job is in LCY, use LCY Non-Deductible VAT amounts directly
+                JobJnlLine."Unit Cost (LCY)" += NonDeductibleVATAmtPerUnitLCY;
